   220|  }
   221|  if (content.length > MAX_COMMIT_CONTENT_LENGTH) {
   222|    throw new Error(`File content is too large for this guarded commit action. Max ${MAX_COMMIT_CONTENT_LENGTH} characters.`);
   223|  }
   224|
   225|  const encodedPath = repoPath.split('/').map((part) => encodeURIComponent(part)).join('/');
   226|  const contentUrl = `https://api.github.com/repos/${repoInfo.owner}/${repoInfo.repo}/contents/${encodedPath}?ref=${encodeURIComponent(branch)}`;
   227|  const existing = await fetchJson(contentUrl, { method: 'GET', headers: await githubHeaders() }).catch(() => null);
   228|  const existingRecord = readRecord(existing?.data);
