   232|    method: 'PUT',
   233|    headers: await githubHeaders(),
   234|    body: JSON.stringify({
   235|      message,
   236|      content: Buffer.from(content, 'utf8').toString('base64'),
   237|      branch,
   238|      ...(existingSha ? { sha: existingSha } : {}),
   239|    }),
   240|  });
