   335|async function runGithubPullRequestStatus(input: Record<string, unknown>): Promise<Record<string, unknown>> {
   336|  const repoInfo = await getGithubRepoInfo(input);
   337|  const number = Number.parseInt(readTrimmed(input.number ?? input.pullNumber), 10);
   338|  if (!Number.isFinite(number) || number <= 0) {
   339|    throw new Error('A valid pull request number is required.');
   340|  }
   341|  const baseUrl = `https://api.github.com/repos/${repoInfo.owner}/${repoInfo.repo}`;
   342|  const pr = await fetchJson(`${baseUrl}/pulls/${number}`, { method: 'GET', headers: await githubHeaders() });
   343|  if (!pr.ok) {
   344|    throw new Error(`GitHub pull request lookup failed with HTTP ${pr.status}.`);
   345|  }
   346|  const data = readRecord(pr.data);
   347|  const headSha = readTrimmed(readRecord(data.head).sha);
   348|  let checksConclusion: string | null = null;
   349|  let checksTotal = 0;
   350|  let checksPassed = 0;
   351|  if (headSha) {
   352|    const checks = await fetchJson(`${baseUrl}/commits/${encodeURIComponent(headSha)}/check-runs`, { method: 'GET', headers: await githubHeaders() });
   353|    if (checks.ok) {
   354|      const runs = Array.isArray(readRecord(checks.data).check_runs) ? readRecord(checks.data).check_runs as Record<string, unknown>[] : [];
   355|      checksTotal = runs.length;
   356|      checksPassed = runs.filter((run) => readTrimmed(run.conclusion) === 'success').length;
   357|      const allDone = runs.every((run) => readTrimmed(run.status) === 'completed');
   358|      checksConclusion = checksTotal === 0 ? 'no_checks' : !allDone ? 'pending' : checksPassed === checksTotal ? 'success' : 'failure';
   359|    }
   360|  }
   361|  return {
   362|    provider: 'github',
   363|    action: 'github_pull_request_status',
   364|    owner: repoInfo.owner,
   365|    repo: repoInfo.repo,
   366|    number,
   367|    state: readTrimmed(data.state) || null,
   368|    merged: data.merged === true,
   369|    mergeable: data.mergeable ?? null,
   370|    mergeableState: readTrimmed(data.mergeable_state) || null,
   371|    headRef: readTrimmed(readRecord(data.head).ref) || null,
   372|    baseRef: readTrimmed(readRecord(data.base).ref) || null,
   373|    headSha: headSha || null,
   374|    checksConclusion,
   375|    checksTotal,
   376|    checksPassed,
   377|    readyToMerge: data.mergeable === true && readTrimmed(data.mergeable_state) !== 'dirty' && (checksConclusion === 'success' || checksConclusion === 'no_checks'),
   378|    url: readTrimmed(data.html_url) || null,
   379|  };
