   382|async function runGithubMergePullRequest(input: Record<string, unknown>): Promise<Record<string, unknown>> {
   383|  const repoInfo = await getGithubRepoInfo(input);
   384|  const number = Number.parseInt(readTrimmed(input.number ?? input.pullNumber), 10);
   385|  if (!Number.isFinite(number) || number <= 0) {
   386|    throw new Error('A valid pull request number is required.');
   387|  }
   388|  const mergeMethodRaw = readTrimmed(input.mergeMethod).toLowerCase();
   389|  const mergeMethod = mergeMethodRaw === 'squash' || mergeMethodRaw === 'rebase' ? mergeMethodRaw : 'merge';
   390|  const baseUrl = `https://api.github.com/repos/${repoInfo.owner}/${repoInfo.repo}`;
   391|
   392|  // Guard: never merge unless checks pass and PR is mergeable, unless explicitly forced by owner.
   393|  const status = await runGithubPullRequestStatus({ ...input, number });
   394|  const requireGreenChecks = !parseBoolean(input.allowFailedChecks);
   395|  if (requireGreenChecks && status.readyToMerge !== true) {
   396|    throw new Error(`Refusing to merge PR #${number}: status checks/mergeability not green (checks=${status.checksConclusion ?? 'unknown'}, mergeableState=${status.mergeableState ?? 'unknown'}). Pass allowFailedChecks=true only to override.`);
   397|  }
   398|  const response = await fetchJson(`${baseUrl}/pulls/${number}/merge`, {
   399|    method: 'PUT',
   400|    headers: await githubHeaders(),
   401|    body: JSON.stringify({ merge_method: mergeMethod }),
   402|  });
   403|  if (!response.ok) {
   404|    throw new Error(`GitHub merge failed with HTTP ${response.status}.`);
   405|  }
   406|  const data = readRecord(response.data);
   407|  return {
   408|    provider: 'github',
   409|    action: 'github_merge_pull_request',
   410|    owner: repoInfo.owner,
   411|    repo: repoInfo.repo,
   412|    number,
   413|    merged: data.merged === true,
   414|    mergeMethod,
   415|    mergeCommitSha: readTrimmed(data.sha) || null,
   416|    checksWereGreen: status.checksConclusion,
   417|    message: readTrimmed(data.message) || null,
   418|  };
